PHA_COLORS = ["#0E91A1", "#09C992", "#09595C", "#9ED3D9", "#6E4AAF", "#EF7356", "#606060"]


def pha_altair_bar(df: pd.DataFrame, x_col: str, y_col: str, title: str):
    if df.empty:
        st.info("لا توجد بيانات لعرضها.")
        return

    chart_df = df.copy()
    chart_df[y_col] = pd.to_numeric(chart_df[y_col], errors="coerce").fillna(0)

    chart = (
        alt.Chart(chart_df)
        .mark_bar(cornerRadiusTopLeft=6, cornerRadiusTopRight=6)
        .encode(
            x=alt.X(f"{x_col}:N", sort="-y", title=None, axis=alt.Axis(labelAngle=0, labelLimit=180)),
            y=alt.Y(f"{y_col}:Q", title=None),
            tooltip=[
                alt.Tooltip(f"{x_col}:N", title=x_col),
                alt.Tooltip(f"{y_col}:Q", title=y_col, format=",")
            ],
            color=alt.value("#0E91A1")
        )
        .properties(title=title, height=380)
    )

    text = (
        alt.Chart(chart_df)
        .mark_text(
            align="center",
            baseline="bottom",
            dy=-5,
            fontSize=12
        )
        .encode(
            x=alt.X(f"{x_col}:N", sort="-y"),
            y=alt.Y(f"{y_col}:Q"),
            text=alt.Text(f"{y_col}:Q", format=",")
        )
    )

    st.altair_chart(chart + text, use_container_width=True)

