def pha_circular_progress(label: str, value: float) -> None:
    value = max(0, min(float(value), 100))
    data = pd.DataFrame({"category": ["النسبة", "المتبقي"], "value": [value, 100 - value]})
    chart = (
        alt.Chart(data)
        .mark_arc(innerRadius=70, outerRadius=95)
        .encode(
            theta=alt.Theta("value:Q"),
            color=alt.Color("category:N", scale=alt.Scale(domain=["النسبة", "المتبقي"], range=["#0E91A1", "#D9D9D9"]), legend=None)
        )
        .properties(width=220, height=220)
    )
    text = alt.Chart(pd.DataFrame({"text": [f"{value:.1f}%"]})).mark_text(
        font="Tahoma", fontSize=28, fontWeight="bold", color="#09595C"
    ).encode(text="text:N")
    st.altair_chart((chart + text), use_container_width=True)
    st.markdown(f"<div style='text-align:center; font-weight:800; color:#09595C;'>{label}</div>", unsafe_allow_html=True)


def filter_by_report_date(df: pd.DataFrame, start_date: date, end_date: date) -> pd.DataFrame:
    if df.empty or "تاريخ إعداد التقرير" not in df.columns:
        return df
    temp = df.copy()
    temp["تاريخ إعداد التقرير"] = pd.to_datetime(temp["تاريخ إعداد التقرير"], errors="coerce").dt.date
    return temp[(temp["تاريخ إعداد التقرير"] >= start_date) & (temp["تاريخ إعداد التقرير"] <= end_date)]


def get_daily_and_cumulative(df: pd.DataFrame, value_col: str, report_end_date: date) -> tuple[int, int]:
    if df.empty or value_col not in df.columns:
        return 0, 0
    cumulative = int(pd.to_numeric(df[value_col], errors="coerce").fillna(0).sum())
    daily = 0
    if "تاريخ إعداد التقرير" in df.columns:
        temp = df.copy()
        temp["تاريخ إعداد التقرير"] = pd.to_datetime(temp["تاريخ إعداد التقرير"], errors="coerce").dt.date
        daily = int(pd.to_numeric(temp.loc[temp["تاريخ إعداد التقرير"] == report_end_date, value_col], errors="coerce").fillna(0).sum())
    return daily, cumulative


# =========================================================
# Helpers
# =========================================================
def load_all_sheets() -> dict:
    ensure_master_file_exists()
    if MASTER_FILE.exists():
        return pd.read_excel(MASTER_FILE, sheet_name=None)
    return {sheet: pd.DataFrame() for sheet in ALL_SHEETS}


def save_all_sheets(sheets: dict) -> None:
    with pd.ExcelWriter(MASTER_FILE, engine="openpyxl") as writer:
        for sheet_name in ALL_SHEETS:
            sheets.get(sheet_name, pd.DataFrame()).to_excel(writer, sheet_name=sheet_name, index=False)


def upsert_port_period_row(sheet_name: str, row: dict) -> None:
    """Add/update one row per port per period."""
    sheets = load_all_sheets()
    new_df = pd.DataFrame([row])
    old_df = sheets.get(sheet_name, pd.DataFrame())

    if not old_df.empty and {"الفترة", "اسم المنفذ"}.issubset(old_df.columns):
        mask = ~(
            (old_df["الفترة"].astype(str) == str(row["الفترة"])) &
            (old_df["اسم المنفذ"].astype(str) == str(row["اسم المنفذ"]))
        )
        old_df = old_df[mask]

    sheets[sheet_name] = pd.concat([old_df, new_df], ignore_index=True)
    save_all_sheets(sheets)


def read_sheet(sheet_name: str) -> pd.DataFrame:
    return load_all_sheets().get(sheet_name, pd.DataFrame())


def make_base_row(period: str, report_date: date, port_name: str) -> dict:
    return {
        "الفترة": period,
        "تاريخ إعداد التقرير": report_date,
        "اسم المنفذ": port_name,
        "وقت الإدخال": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    }


def save_simple_value(sheet_name: str, period: str, report_date: date, port_name: str, value_label: str, value: int) -> None:
    row = make_base_row(period, report_date, port_name)
    row[value_label] = value
    upsert_port_period_row(sheet_name, row)


def save_requirement_value(
    sheet_name: str,
    period: str,
    report_date: date,
    port_name: str,
    arrivals: int,
    compliant: int
) -> None:
    non_compliant = arrivals - compliant
    compliance_rate = compliant / arrivals if arrivals else 0

    row = make_base_row(period, report_date, port_name)
    row["عدد القادمين"] = arrivals
    row["عدد الملتزمين"] = compliant
    row["غير الملتزمين"] = non_compliant
    row["نسبة الالتزام"] = compliance_rate

    upsert_port_period_row(sheet_name, row)


def upsert_africa_row(row: dict) -> None:
    """Add/update one row per period + port + nationality."""
    sheets = load_all_sheets()
    new_df = pd.DataFrame([row])
    old_df = sheets.get(SHEET_AFRICA_TARGETED, pd.DataFrame())

    required_cols = {"الفترة", "اسم المنفذ", "الجنسية"}
    if not old_df.empty and required_cols.issubset(old_df.columns):
        mask = ~(
            (old_df["الفترة"].astype(str) == str(row["الفترة"])) &
            (old_df["اسم المنفذ"].astype(str) == str(row["اسم المنفذ"])) &
            (old_df["الجنسية"].astype(str) == str(row["الجنسية"]))
        )
        old_df = old_df[mask]

    sheets[SHEET_AFRICA_TARGETED] = pd.concat([old_df, new_df], ignore_index=True)
    save_all_sheets(sheets)


def save_africa_targeted_row(
    period: str,
    report_date: date,
    port_name: str,
    nationality: str,
    pilgrims: int,
    other: int,
    suspected_cases: int
) -> None:
    total = pilgrims + other
    row = make_base_row(period, report_date, port_name)
    row["الجنسية"] = nationality
    row["معتمرين"] = pilgrims
    row["أخرى"] = other
    row["الإجمالي"] = total
    row["حالات الاشتباه"] = suspected_cases
    upsert_africa_row(row)


